def mode_count(nums):
    if not nums:
        return 0

    frequency = {}
    for num in nums:
        frequency[num] = frequency.get(num, 0) + 1

    max_freq = max(frequency.values())
    mode_count = 0
    for num, freq in frequency.items():
        if freq == max_freq:
            mode_count += 1
    return mode_count
